import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;
import java.util.concurrent.locks.ReentrantLock;

public class BankingApp {
    
    private Connection connection;
    private ReentrantLock lock = new ReentrantLock();
    
    public BankingApp() {
        try {
            connection = DriverManager.getConnection("jdbc:myDriver:myDatabase", "user", "password");
        } catch (SQLException e) {
            e.printStackTrace();
        }
    }

    public void processTransaction(int accountId, double amount) {
        try {
            lock.lock();
            if(isValidTransaction(accountId, amount)) {
                updateBalance(accountId, amount);
            } else {
                System.out.println("Invalid transaction");
            }
        } catch (Exception e) {
            e.printStackTrace();
        } finally {
            lock.unlock();
        }
    }

    private boolean isValidTransaction(int accountId, double amount) throws SQLException {
        String query = "SELECT balance FROM accounts WHERE id = ?";
        PreparedStatement pstmt = connection.prepareStatement(query);
        pstmt.setInt(1, accountId);
        ResultSet rs = pstmt.executeQuery();
        if(rs.next()) {
            double currentBalance = rs.getDouble("balance");
            return amount <= currentBalance;
        }
        return false;
    }

    private void updateBalance(int accountId, double amount) throws SQLException {
        String updateSql = "UPDATE accounts SET balance = balance - ? WHERE id = ?";
        PreparedStatement pstmt = connection.prepareStatement(updateSql);
        pstmt.setDouble(1, amount);
        pstmt.setInt(2, accountId);
        pstmt.executeUpdate();
    }
}